// auth.ts
import { db } from './db';

export class AuthService {
  private cache: Map<string, User> = new Map();
  private rateLimiter: RateLimiter;

  constructor(private db: Database, private secret: string) {
    this.rateLimiter = new RateLimiter({ max: 100 });
  }

  async authenticate(username: string, password: string): Promise<User | null> {
    /** Verify credentials and return User or null. */
    if (this.rateLimiter.isLimited(username)) return null;
    const user = await this.db.findUser(username);
    if (user && await bcrypt.compare(password, user.passwordHash)) {
      this.cache.set(username, user);
      return user;
    }
    return null;
  }

  async createSession(user: User): Promise<string> {
    /** Create a new JWT session token. */
    return jwt.sign({ userId: user.id, role: user.role }, this.secret, { expiresIn: '24h' });
  }

  async validateSession(token: string): Promise<User | null> {
    /** Validate JWT and return user. */
    try {
      const payload = jwt.verify(token, this.secret);
      return await this.db.findUserById(payload.userId);
    } catch {
      return null;
    }
  }
}
